          + '<div class="inc-tipo">' + (i.tipoNombre || '') + '</div>'
          + '<span class="chip" style="background:' + gravBg(i.gravedad) + ';color:' + gravColor(i.gravedad) + '">' + gravLabel(i.gravedad) + '</span>'
